--
-- 表的结构 `casual`
--

CREATE TABLE `casual` (
  `id` int(11) NOT NULL,
  `author` varchar(255) DEFAULT NULL,
  `content` varchar(255) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `upt_act` varchar(255) DEFAULT NULL,
  `sort` int(11) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

--
-- 转存表中的数据 `casual`
--

INSERT INTO `casual` (`id`, `author`, `content`, `created_at`, `updated_at`, `upt_act`, `sort`) VALUES
(1, '功夫熊猫', '你患得患失，太在意从前又太担心将来，有句话说得好，昨天是段历史，明天是个谜团，而今天是天赐的礼物，要像珍惜礼物那样珍惜今天', '2024-06-09 12:38:38', '2024-06-09 12:38:41', 'I', 1),
(2, '爱情公寓', '我们常常看到的风景是，一个人，总是仰望和羡慕着别人的幸福，其实，每个人都是幸福的，只是你的幸福常常在被人眼里。', '2024-06-09 14:55:42', '2024-06-09 14:55:42', 'I', 2),
(3, 'cxzczx', 'vcdsv', '2024-06-09 14:56:15', '2024-06-09 14:56:15', 'D', 3),
(4, 'gtr', 'gt', '2024-06-09 16:17:18', '2024-06-09 16:17:18', 'D', 1),
(5, '村上春树', '如果你爱我，而我恰好也爱你，你头发乱了的时候我会笑笑替你拨一拨，然而手还留恋在你头上多待几秒，但是，如果我爱你，而你不巧的不爱我，你头发乱了，我只会轻轻地告诉你，你头发乱了。期待有一天，能够听到那一句，那你替我拨一拨吧', '2024-06-09 16:36:36', '2024-06-09 16:36:36', 'I', 3),
(6, '无', '如果你够即时，能赶上这个冬天与我一起吃火锅喝奶茶，看电影放烟花，那么这个冬天一定很美好。如果你这个冬天不来，那我就买长一点的衣服，把手塞到袖子里，等到来年你一定要牵起我冷了一个冬天的手', '2024-06-09 16:36:55', '2024-06-09 16:36:55', 'D', 4),
(7, NULL, '太阳也许会使我融化，但我依然向往', '2024-06-09 16:37:11', '2024-06-09 16:37:11', 'I', 5),
(8, '网易云', '在一切变好之前，我们总要经历一些不开心的日子 这段日子也许很长，也许只是一觉醒来 耐心点，给好运一点时间 你要相信，每件事的最后都会是好事 如果没有 就说明还没到最后', '2024-06-09 16:37:34', '2024-06-09 16:37:34', 'I', 6),
(9, NULL, '你身上的裂痕，那是光照进来的地方', '2024-06-09 16:37:55', '2024-06-09 16:37:55', 'I', 8),
(10, NULL, '我打从心底里相信，世界上80%的恋爱关系都是狗屎，一群没花时间学习如何和自己独处的人，因此也从未学习如何爱他们自己，于是你就请别人来替你完成。', '2024-06-11 19:49:46', '2024-06-11 19:49:46', 'D', 3),
(11, NULL, '我打从心底里相信，世界上80%的恋爱关系都是狗屁，一群没花时间学习如何和自己独处的人，因此也从未学习如何爱他们自己，于是你就请别人来替你完成。', '2024-06-11 19:50:01', '2024-06-11 19:50:01', 'I', 4),
(12, NULL, '水面的涟漪虽然暂时消散了，但仍有人记得，风曾经吹过', '2024-06-11 19:54:16', '2024-06-11 19:54:16', 'I', 9),
(13, '杀死一只知更鸟', '没必要把你懂的所有东西都说出来，人们不喜欢他们身边有人比他们懂得更多，那会让他们很恼火。', '2024-06-11 19:57:35', '2024-06-11 19:57:35', 'I', 10),
(14, '晚上', '梦是夜晚被撕开的一个口子，在另一个世界，我们都能见到相见的人', '2024-06-11 19:59:43', '2024-06-11 19:59:43', 'D', 11),
(15, '雨', '乌云和白云结婚，我们欢呼着，去见他们撒下的喜糖', '2024-06-11 20:00:43', '2024-06-11 20:00:43', 'I', 12),
(16, '', '希君生羽翼，一化北溟鱼 --李白', '2024-06-11 20:03:07', '2024-06-11 20:03:07', 'I', 13),
(17, NULL, '东隅已逝，桑榆非晚', '2024-06-11 20:03:29', '2024-06-11 20:03:29', 'I', 14),
(18, '', '如果你够即时，能赶上这个冬天与我一起吃火锅喝奶茶，看电影放烟花，那么这个冬天一定很美好。如果你这个冬天不来，那我就买长一点的衣服，把手塞到袖子里，等到来年你一定要牵起我冷了一个冬天的手', '2024-06-11 20:03:51', '2024-06-11 20:03:51', 'I', 15),
(19, '英雄联盟', '梦里出现的人，是醒来不能说话的人。', '2024-06-11 20:07:33', '2024-06-11 20:07:33', 'I', 16),
(20, '四库全书', '一岁一礼，一寸欢喜', '2024-06-11 20:08:40', '2024-06-11 20:08:40', 'I', 15),
(21, '晚上', '梦是夜晚被撕开的一个口子，在另一个世界，我们都能见到想见的人', '2024-06-11 20:09:41', '2024-06-11 20:09:41', 'I', 11),
(22, NULL, '如果我的一生见过雪 踏过浪 也牵过爱人的手 我就变成一颗松果 变成半只贝壳 变成挣扎的心脏 于是我就不盼望春天 不赞美海底 蹦蹦跳跳 下一秒就死去 永远沉溺于失去前的最后一秒 我践踏着浪漫走向永眠走向岸边 我丰富而慷慨 帮助人们获得爱又把自己关进冬天 等另一个自己出现', '2024-06-15 11:55:00', '2024-06-15 11:55:00', 'I', 17),
(23, NULL, '人生最大的捷径就是打扮自己，人的运气跟打扮真的很有关系，言语压君子，衣帽正小人，先敬罗衣后敬人。其实很多时候你和别人见面，他们首先都是看你的穿搭，其次询问你的家庭背景和以及谋生方式，以便在心里计算出对你的尊重程度，所以，千万不要放弃打扮和爱美这件事。', '2024-06-20 22:51:22', '2024-06-20 22:51:22', 'I', 18),
(24, NULL, '每个人都在说离校的那天要好好的再看一眼学校和宿舍，但每个人都在最后一天顶着烈日拖着行李匆忙离开，连头也忘记了回。', '2024-06-21 23:16:33', '2024-06-21 23:16:33', 'I', 19),
(25, '你走以后', '如果季节更替，树叶落地，银色满季，没能回到过去，我在做个梦给你', '2024-06-27 14:48:14', '2024-06-27 14:48:14', 'I', 3),
(26, NULL, '活在喜欢的状态里才是活着', '2024-11-21 18:27:40', '2024-11-21 18:27:40', 'I', 20),
(27, NULL, '不去管别人跟你不开心的事。人生啊，光是让自己奋斗与努力就已经筋疲力尽了不是吗', '2024-12-19 11:13:37', '2024-12-19 11:13:37', 'I', 30);

