INSERT INTO `essay_note` (`id`, `essay_id`, `html`, `created_at`, `updated_at`, `upt_act`) VALUES
(1, 25, '<h3 style=\"text-align: left;\">Call和apply有什么区别？</h3><p style=\"text-align: left; line-height: 2;\">JavaScript中的call()和apply()方法都是用来改变函数中this的指向的，它们的区别在于传参方式不同。 call()方法接收的是一个参数列表，而apply()方法接收的是一个数组。</p><pre style=\"text-align: left;\"><code style=\"text-align: left; line-height: 1.5;\">function func(arg1, arg2, arg3) {\n  console.log(this, arg1, arg2, arg3);\n}\nconst obj = { name: \'Tom\' };\nfunc.call(obj, 1, 2, 3); // 输出{ name: \'Tom\' } 1 2 3\nfunc.apply(obj, [1, 2, 3]); // 输出{ name: \'Tom\' } 1 2 3</code></pre><p><br></p>', '2024-03-07 14:31:14', '2024-03-07 14:31:16', 'D'),
(2, 34, '111', '2024-03-07 15:57:04', '2024-03-07 15:57:04', 'D'),
(3, 52, '<p>22222fdsfsdfsd</p>', '2024-03-07 16:06:16', '2024-03-07 16:06:16', 'U'),
(4, 25, '<p>1211</p>', '2024-03-11 12:05:27', '2024-03-11 12:05:27', 'I'),
(5, 66, '<p>随便做个笔记</p>', '2024-09-13 18:09:27', '2024-09-13 18:09:27', 'U'),
(6, 65, '<p>这需要一个笔记</p>', '2024-09-13 18:10:51', '2024-09-13 18:10:51', 'I'),
(7, 66, '<h3>业务开发：</h3><p> &nbsp; &nbsp;1. 工作流程改进：</p><p><img src=\"http://117.50.179.27:7001/public/uploads/2024/10/21/1729512815415676.png\" alt=\"\" data-href=\"\" style=\"\"/></p><p>在参与完SA导入后，需要有个自己整理业务流程的过程，然后再是coding</p>', '2024-09-14 16:33:52', '2024-09-14 16:33:52', 'D'),
(8, 67, '<h3>业务开发：</h3><p> &nbsp; &nbsp;1. 工作流程改进：</p><p><img src=\"http://117.50.179.27:7001/public/uploads/2024/10/21/1729512815415676.png\" alt=\"\" data-href=\"\" style=\"\"/></p><p>在参与完SA导入后，需要有个自己整理业务流程的过程，然后再是coding</p><p>整理业务流程时，可以多参考prd以及UX图整理，</p><p>比如邀请有礼的操作步骤，在单看UI图并不能直观地看出所有的流程以及步骤，可以结合UX图的流程走一遍，通过自己mock数据来整理所有的流程，接着再进行coding。</p>', '2024-10-25 15:35:15', '2024-10-25 15:35:15', 'I'),
(9, 71, '<p>nrm经常需要重新安装</p>', '2025-01-26 10:42:13', '2025-01-26 10:42:13', 'D'),
