--
-- 表的结构 `project`
--

CREATE TABLE `project` (
  `id` int(11) NOT NULL COMMENT '主键',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `link` varchar(255) DEFAULT NULL COMMENT '项目预览链接',
  `coverUrl` varchar(255) DEFAULT NULL COMMENT '封面',
  `html` text COMMENT '项目内容',
  `upt_act` varchar(2) DEFAULT NULL COMMENT '字段状态，U表示更新，D表示已删除，I表示正常',
  `created_at` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL COMMENT '更新时间',
  `state` int(11) DEFAULT NULL COMMENT '1为发布，2为不发布'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

--
-- 转存表中的数据 `project`
--

INSERT INTO `project` (`id`, `title`, `link`, `coverUrl`, `html`, `upt_act`, `created_at`, `updated_at`, `state`) VALUES
(1, '欧美特卫浴', '暂无部署', '/public/uploads/2024/06/05/1717594272284220.jpg', '<p>大二时期写的第一个项目，包括前台和后台，后端</p><p><br></p><p><br></p><h3>前台主要功能：</h3><p>展示卫浴轮播图；</p><p>根据赞的获取数量展示销售榜单；</p><p>通过分类查找需要的卫浴图片；</p><p><br></p><h3>后台主要功能：</h3><p>对轮播图增删改查；</p><p>对产品增删改查；</p><p>在产品中添加畅销榜单；</p><p><br></p><h3>主要难点与解决方案：</h3><p>头部组件的制作：如何在变化路由时控制下划线的位置，移至二级菜单时，下划线不能移动等等</p><p>解决：通过watch监听重新初始化</p><p>后台图片预览：当图片上传后不能直接传到服务器，而是先预览，在确定新增或修改等操作后，再调用接口</p><h3>解决方案：：</h3><pre><code class=\"language-javascript\">      // 创建一个读取对象\n      var reader = new FileReader();\n      // 将文件转化为一个二进制字符串\n      reader.readAsArrayBuffer(file.raw);\n      // 监听文件读取完成\n      reader.onload = (e) =&gt; {\n      // 监听完成后，将二进制字符串转化为Blob对象，并且通过URL.createObjectURL创建一个url，指向该Blob对象\n      let data = window.URL.createObjectURL(new Blob([e.target.result]));\n      // 将生成的url赋值给需要预览的url\n      this.imgurl = data;</code></pre><p><br></p>', 'U', '2023-05-14 22:55:30', '2023-05-14 22:55:32', 2),
(2, 'blog网站', '前台：http://117.50.179.27\n\n后台：http://117.50.179.27:81 用户账号(youke,888888)\n', '/public/uploads/2023/04/21/1682061056437239.png', '<p>一个简易博客网站</p><p><br></p><p>网站制作初心只是为了自己对前后端开发的学习，提高自身的技术能力，主要的功能如下：</p><p><br></p><ol><li style=\"text-align: start; line-height: 2;\">内容发布：博客最核心的功能是能够让用户发布和管理自己的文章内容。</li><li style=\"text-align: start; line-height: 2;\">评论：让用户在文章下方进行评论，与其他读者互动、讨论。</li><li style=\"text-align: start; line-height: 2;\">分类：主要以领域划分，以自身的技术栈展开划分，分html，css，js，vue，node，其他</li><li style=\"text-align: start; line-height: 2;\">收藏：让读者可以查看喜欢的文章。</li><li style=\"text-align: start; line-height: 2;\">搜索：提供一个搜索框让读者可以搜索相关的文章和内容。</li><li style=\"text-align: start; line-height: 2;\">自定义主题：可以让用户根据自己的喜好，自定义博客的风格和样式。</li><li style=\"text-align: start; line-height: 2;\">数据统计：可以让用户了解博客的流量、访问来源、用户行为等数据信息，方便用户优化博客和改进写作。（开发中）</li><li style=\"text-align: start; line-height: 2;\">管理：管理员账户可以帮助博主管理自己的发布、评论等操作。</li></ol><p style=\"text-align: start; line-height: 2;\"><br></p><p style=\"text-align: start; line-height: 2;\">项目难点：</p><p style=\"text-align: start; line-height: 2;\"><br></p><ol><li style=\"text-align: start; line-height: 2;\">界面和用户体验：博客需要具备良好的界面设计和用户体验，能让用户方便、快捷地浏览和使用博客。</li></ol><p style=\"text-align: start; line-height: 2;\">如何解决：<span style=\"color: rgb(36, 41, 47); font-size: 14px;\">使用媒体查询等等做页面优化，兼容。</span></p><p style=\"text-align: start; line-height: 2;\">2. &nbsp;数据库设计和安全管理：博客需要有一个结构化、高效、安全的数据库管理系统，用于保存和处理博客的各种数据信息。</p><p style=\"text-align: start; line-height: 2;\">如何解决：首先一个jwt权限管理，输入框的文字长度限制等等</p><p style=\"text-align: start; line-height: 2;\">3. &nbsp;性能优化：制作之初，页面访问卡顿</p><p style=\"text-align: start; line-height: 2;\">如何解决：删除不必要的dom操作，图片懒加载，</p><p style=\"text-align: start; line-height: 2;\">4. &nbsp;后台动态路由的实现</p><p style=\"text-align: start; line-height: 2;\">如何解决：</p><ol><li style=\"text-align: start; line-height: 2;\">让每个用户有自己的菜单数组，通过管理用户的菜单数组对其页面的访问进行控制</li></ol><p style=\"text-align: start; line-height: 2;\">2. &nbsp;实现动态路由生成：在 Vue Router 实例化时，通过后台接口请求返回的用户权限列表，根据权限列表动态生成路由，可以使用 addRoutes 方法。</p><p style=\"text-align: start; line-height: 2;\">5. &nbsp;权限管理：每个角色对应不同的权限</p><p style=\"text-align: start; line-height: 2;\">如何解决：</p><p style=\"text-align: start; line-height: 2;\">首先是数据库设计分三个表，角色用户列表，角色列表，用户列表，每个用户都对应着一个角色，每个角色又有对应的menu列表，通过更改角色对应的menu列表每个页面的状态来控制角色对他的权限。</p><p style=\"text-align: start; line-height: 2;\"><br></p><p><br></p>', 'U', '2023-05-17 23:13:42', '2023-05-17 23:13:45', 1),
(3, 'vue3+ts+vitepress组件库', 'github：https://github.com/xielinchang/demo-ui\n\n线上文档站地址：http://117.50.179.27:82\n\n包已上传至npm官网，可直接使用\n包的名称是joyd-demo，  可通过npm i joyd-demo，yarn add joyd-demo进行下载', '/public/uploads/2023/05/23/1684852666864368.png', '<p style=\"line-height: 2;\">2023寒假期间字节青训营写的vue3组件库，包括各类常用组件以及文档站的编写，由于写的人数不多且有些人对vue3不熟悉，所以组件数和功能性不全，</p><p style=\"line-height: 2;\">以下是文档站的一些截图</p><p style=\"line-height: 2;\">线上文档站地址：<a href=\"http://117.50.179.27:82\" target=\"_blank\">http://117.50.179.27:82</a></p><p style=\"line-height: 2;\"><img src=\"http://117.50.179.27:7001/public/uploads/2023/10/26/1698290111816485.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 2;\"><br></p><p style=\"line-height: 2;\"><img src=\"http://117.50.179.27:7001/public/uploads/2023/10/26/1698290281240202.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 2;\"><br></p><p><br></p><p><img src=\"http://117.50.179.27:7001/public/uploads/2023/10/26/1698290322518631.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p><p style=\"line-height: 2;\"><br></p><p><br></p><p><img src=\"http://117.50.179.27:7001/public/uploads/2023/10/26/1698290374449161.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p><p><br></p><p><br></p><p><img src=\"http://117.50.179.27:7001/public/uploads/2023/10/26/1698290498604337.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p><p style=\"line-height: 2;\"><br></p><h3 style=\"line-height: 2;\">主要组件：</h3><p style=\"line-height: 2;\">返回顶部，按钮，卡片，计数器, &nbsp;对话框，icon图标，消息框，分页，选择下拉框， 消息提示，tooltip提示。</p><p style=\"line-height: 2;\"><br></p><h3 style=\"line-height: 2;\">主要难点：</h3><h3 style=\"line-height: 2;\">消息提示</h3><p style=\"line-height: 2;\">1.动画和过渡</p><pre><code class=\"language-html\"> &lt;transition name=\"message-fade\" @after-leave=\"onAfterLeave\"&gt;\n    &lt;div v-if=\"visible\" :class=\"[createBEM(), createBEM(\'--\' + type)]\"&gt;\n      &lt;JIcon :name=\"iconMap[type]\" :class=\"type === \'loading\' && \'is-loading\'\"&gt;&lt;/JIcon&gt;\n      &lt;div :class=\"[createBEM(\'content\')]\"&gt;\n        &lt;slot&gt;{{ content }}&lt;/slot&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n  &lt;/transition&gt;\n  \n </code></pre><pre><code class=\"language-css\">  .message-fade-enter-from,\n  .message-fade-leave-to {\n    opacity: 0;\n    transform: translate(-50%, -100%);\n  }</code></pre><p style=\"line-height: 2;\">2.定义全局方法</p><pre><code class=\"language-typescript\">// 定义 message 函数\nconst message = ((options) =&gt; {\n  // 创建 message 应用实例\n  const messageApp = createApp(MessageComponent, handleOptions(options));\n  // 在屏幕上展示 message\n  const vm = showMessage(messageApp);\n\n  // 隐藏 message 的方法\n  function hideMessage() {\n    vm.setVisible(false);\n  }\n\n  // 将 hideMessage 方法作为 message 函数的返回值\n  return hideMessage;\n}) as Message;\n\n// 遍历 types 数组\ntypes.forEach((type) =&gt; {\n  // 向 message 函数添加相应类型的方法，该方法中调用了 message 函数，并将 type 参数合并到 options 中\n  message[type] = (options) =&gt; message({ ...handleOptions(options), type });\n});</code></pre><p style=\"line-height: 2;\">3.挂载到页面上</p><p style=\"line-height: 2;\">vue3</p><pre><code class=\"language-javascript\">// 创建根元素\nfunction createRootDom() {\n  const div = document.createElement(\'div\');\n  div.setAttribute(\'id\', prefixCls);\n  return document.body.appendChild(div);\n}\n\n// 在屏幕上展示 message 组件\nfunction showMessage(app: App) {\n  // 查找根元素\n  let rootDom = document.getElementById(prefixCls);\n  if (!rootDom) {\n    // 如果根元素不存在，创建一个新的根元素\n    rootDom = createRootDom();\n  }\n</code></pre><p style=\"line-height: 2;\">vue2:</p><p style=\"line-height: 2;\">1.位置的迭代</p><pre><code class=\"language-javascript\">  instance = new MessageConstructor({\n    data: options\n  })\n  instance.id = id\n  //挂载实例\n  instance.$mount()\n  //添加元素\n  document.body.appendChild(instance.$el)\n  //设置默认高度\n  let verticalOffset = options.offset || 30\n  //多个消息同时出现时计算遍历高度，使之不重合\n  instances.forEach(item =&gt; {\n    verticalOffset += item.$el.offsetHeight + 16\n  })\n  instance.verticalOffset = verticalOffset\n  instance.visible = true\n  instances.push(instance)\n  return instance\n}\n//消息关闭\nMessage.close = function(id, userOnClose) {\n  const len = instances.length\n  let index = -1\n  let removedHeight\n  for (let i = 0; i &lt; len; i++) {\n    if (id === instances[i].id) {\n      removedHeight = instances[i].$el.offsetHeight\n      index = i\n      if (typeof userOnClose === \'function\') {\n        userOnClose(instances[i])\n      }\n      instances.splice(i, 1)\n      break\n    }\n  }\n  if (len &lt;= 1 || index === -1 || index &gt; instances.length - 1) return\n  for (let i = index; i &lt; len - 1; i++) {\n    const dom = instances[i].$el\n    dom.style[\'top\'] =\n        parseInt(dom.style[\'top\'], 10) - removedHeight - 16 + \'px\'\n  }\n}\n// 最后在main.js\nimport msg from \'组件路径\'\nVue.prototype.$msg = msg // 注册消息事件</code></pre><p style=\"line-height: 2;\">还有一些细节难点：</p><p style=\"line-height: 2;\">比如在网络出现问题时需要给出一些设置以保证更好的用户体验</p><ol><li style=\"line-height: 2;\">错误处理：如果网络请求失败，你的组件应该能够捕获这个错误，并显示一个有用的错误消息。这可能需要使用try/catch语句，或者在Promise中使用.catch()方法。</li><li style=\"line-height: 2;\">超时设置：如果网络请求花费的时间过长，你的组件应该能够识别这个问题，并显示一个超时的消息。这可能需要使用setTimeout()函数，或者在fetch()或XMLHttpRequest对象中设置一个超时值。<br></li></ol><p style=\"line-height: 2;\"><br></p><h3 style=\"line-height: 2;\">toolTip提示、消息提示</h3><p style=\"line-height: 2;\">tooltip位置的计算:</p><pre><code class=\"language-javascript\">  function getStyle() {\n    // 获取tooltipRef的DOM矩形，若存在则执行下面的代码块\n    const tooltipRect = tooltipRef.value?.getBoundingClientRect();\n    if (tooltipRect) {\n      // 从props中获取弹出框的方向信息，比如top、right、bottom、left等\n      const direction = props.placement;\n      // 如果方向是top或bottom\n      if ([\'top\', \'bottom\'].includes(direction)) {\n        // 计算内容的垂直偏移距离 使tooltip移出元素为  元素本身高度再+10的箭头高度\n        const value = tooltipRect.height + 10;\n        const y = direction === \'top\' ? -value : value;\n        // 设置contentStyle对象的transform属性，使内容沿Y轴平移\n        contentStyle.value = {\n          transform: `translate(-50%, ${y}px)`,\n        };\n      } else {\n        // 否则方向为left或right\n        // 计算内容的水平偏移距离\n        const value = tooltipRect.width + 10;\n        const x = direction === \'left\' ? -value : value;\n        // 设置contentStyle对象的transform属性，使内容沿X轴平移\n        contentStyle.value = {\n          transform: `translate(${x}px, -50%)`,\n        };\n      }\n    }\n  }</code></pre><h3 style=\"line-height: 2;\">拖拽对话框</h3><p style=\"line-height: 2;\">拖拽缩放对话框(拖拽的实现方法):</p><pre><code class=\"language-html\">&lt;div class=\"dragger-wrap\"&gt;\n      &lt;div\n        ref=\"wrapper\"\n        class=\"dragger\"\n        :style=\"{\n          transform: `translate(${topoX}px, ${topoY}px) scale(${topoScale})`,\n        }\"\n        @mousewheel.stop.prevent=\"onMouseWheel\"\n        @mousedown=\"onMouseDown\"\n      &gt;\n        &lt;span&gt;\n          拖拽&缩放\n        &lt;/span&gt;&lt;/div&gt;\n    &lt;/div&gt;</code></pre><pre><code class=\"language-javascript\">onMouseDown(event) {\n      // 记录鼠标按下时的初始位置和元素的初始位置\n      const startX = event.clientX\n      const startY = event.clientY\n\n      // 获取元素当前的位置\n      const wrapper = this.$refs.wrapper\n      const transformStyle = window\n        .getComputedStyle(wrapper)\n        .getPropertyValue(\'transform\')\n      const transformMatrix = new DOMMatrix(transformStyle)\n      const currentTranslateX = transformMatrix.m41\n      const currentTranslateY = transformMatrix.m42\n\n      const onMouseMove = (e) =&gt; {\n        // 计算鼠标移动的偏移量\n        const offsetX = e.clientX - startX\n        const offsetY = e.clientY - startY\n        // 更新元素的位置为初始位置加上偏移量和当前位置\n        this.topoX = currentTranslateX + offsetX\n        this.topoY = currentTranslateY + offsetY\n      }\n\n      const onMouseUp = () =&gt; {\n        // 解除事件绑定\n        document.removeEventListener(\'mousemove\', onMouseMove)\n        document.removeEventListener(\'mouseup\', onMouseUp)\n      }\n\n      // 绑定鼠标移动和释放事件\n      document.addEventListener(\'mousemove\', onMouseMove)\n      document.addEventListener(\'mouseup\', onMouseUp)\n    },\n    onMouseWheel(event) {\n      // 设置元素缩放  这里使用transform: scale实现；你也可以使用 zoom 来实现\n      let scale = this.topoScale * 100\n      scale += event.wheelDelta / 10\n      // 限制最小缩小到20%\n      if (scale &lt; 20) {\n        scale = 20\n      }\n      // 限制最大可放大到3倍\n      if (scale &gt; 300) {\n        scale = 300\n      }\n      // 设置元素transform\n      if (scale &gt; 0) {\n        this.topoScale = scale / 100\n      }\n      return false\n    }</code></pre><h3 style=\"line-height: 2;\">分页器</h3><p style=\"line-height: 2;\">分页器的...位置计算</p><pre><code class=\"language-javascript\">// 计算分页按钮总数的中间位置\n      const center = Math.ceil(props.pageCount / 2);\n      // 当前页处于靠近首页的位置\n      if (props.currentPage &gt;= 1 && props.currentPage &lt;= center) {\n        let firstList = [];\n        if (props.pageCount == 1) {\n          firstList.push(1);\n        } else {\n          for (let i = 0; i &lt;= props.pageCount; i++) {\n            if (i &lt; props.pageCount - 1) {\n              firstList.push(1 + i);\n            } else if (i == props.pageCount - 1) {\n              firstList.push(\'...\');\n            } else {\n              firstList.push(pageTotal.value);\n            }\n          }\n        }\n        return firstList;\n      } else if (\n        props.currentPage &lt;= pageTotal.value &&\n        props.currentPage &gt;= pageTotal.value - center + 1\n      ) {\n        // 当前页处于靠近尾页的位置\n        let firstList = [];\n        if (props.pageCount == 1) {\n          firstList.push(pageTotal.value);\n        } else {\n          for (let i = props.pageCount; props.pageCount &gt;= i && i &gt;= 0; i--) {\n            if (i &gt; props.pageCount - 1) {\n              firstList.push(1);\n            } else if (i == props.pageCount - 1) {\n              firstList.push(\'...\');\n            } else {\n              firstList.push(pageTotal.value - i);\n            }\n          }\n        }\n        return firstList;\n      } else {\n        // 当前页处于中间页的位置\n        let firstList = [];\n        firstList.push(1);\n        firstList.push(\'...\');\n        let justCenter = Math.ceil((props.pageCount - 2) / 2);\n        for (let i = 1; i &lt;= props.pageCount - 2; i++) {\n          if (i &lt; justCenter) {\n            firstList.push(props.currentPage - (justCenter - i));\n          } else if (i == justCenter) {\n            firstList.push(props.currentPage);\n          } else {\n            firstList.push(props.currentPage + (i - justCenter));\n          }\n        }\n        firstList.push(\'...\');\n        firstList.push(pageTotal.value);\n        return firstList;\n      }</code></pre><h3 style=\"line-height: 2;\">项目心得：</h3><p style=\"line-height: 2;\">之前没有接触过vue3，这是第一次接触vue3，所以学到了vue3与vue2不同之处，对setup语法糖有了基础的认知，对组件封装，挂载，原型等有了新的认识，自己也用vue2仿照该项目进行练习。</p><p style=\"line-height: 2;\">了解了vitepress文档站，认识和学习了文档站的基础配置和如何书写文档站。</p>', 'U', '2023-05-14 22:55:30', '2023-05-14 22:55:32', 1),
(4, '', '', '', '<p> hhh</p>', 'D', '2023-05-14 22:55:30', '2023-05-14 22:55:32', 1),
(5, '锐捷网络实习项目', '暂无链接，由于公司机密性，不可外传代码', '/public/uploads/2023/11/11/1699676045443755.png', '<p style=\"line-height: 2;\">锐捷网络实习经历</p><p style=\"line-height: 2;\"><strong>项目一：新地推</strong></p><p style=\"line-height: 2;\">主要负责将原先uni-app的代码转化为h5的代码，并添加新的功能点和接口</p><p style=\"line-height: 2;\">最开始做的页面，没有很复杂的逻辑部分，主要是保证页面的高保真。</p><p style=\"line-height: 2;\"><strong>项目二：睿易云系统</strong></p><p style=\"line-height: 2;\">主要负责对新UI的系统进行添加新功能和新页面，对新UI页面中的词条进行国际化处理，</p><p style=\"line-height: 2;\">碰到的难点：系统比较庞大，做的点也比较复杂，比较复杂的有：时间的不同格式化，因为传回阶扣参数的需求，要对时间戳进行不同的格式化，</p><p style=\"line-height: 2;\">对一些必要的图片实现拖拽和缩放，实现对新版本的导航说明功能，帮助用户理解新增的功能如何使用。</p><p style=\"line-height: 2;\"><strong>项目三：词条管理系统</strong></p><p style=\"line-height: 2;\">是个用于内部开发的小语种管理系统</p><p style=\"line-height: 2;\">配合后端人员，负责页面和功能的总体实现</p><p style=\"line-height: 2;\">难点：主要是对组件的灵活应用，有些antd组件没有的功能，需要对其进行拓展，</p><p style=\"line-height: 2;\">比如：</p><p style=\"line-height: 2;\">1.表格全选</p><p style=\"line-height: 2;\">这里有个小问题，如果数据超过一页，点击全选，他自己会默认选中当前页的10个数据,导致selectedRowKeys的数据缺失。打印出来的数据是没有11-20个的，但是操作数据是生效了的只是妨碍是否全选的判断，目前解决是在数组长度判断上+10</p><p style=\"line-height: 2;\">2.可编辑表格的所有属性</p><p style=\"line-height: 2;\">antd只支持对单个属性或者整行属性可编辑，需要对所有属性二次循环赋值editable属性，让所有属性变为可编辑</p><p style=\"line-height: 2;\">3.词条管理有个antd表格需要进行拓展，实现在antd原有功能基础上添加一个筛选属性名的功能，</p><p style=\"line-height: 2;\">解决，利用render进行重渲染，通过slots循环先获取原有属性，再对其进行拓展，属性名通过被选中的语种进行显示即可</p><p style=\"line-height: 2;\"><strong>项目四：产品管理</strong></p><p style=\"line-height: 2;\">目前最新开发的系统，负责页面的实现</p><p style=\"line-height: 2;\">主要难点：手写柱状图，漏斗图，一些不规则图形的实现</p><p style=\"line-height: 2;\">解决： 利用css的clip-path: polygon()进行裁剪，还有就是利用border进行挤压可以实现一些想要的图形，还有就是 transform: perspective()可以进行3D视图效果来实现。</p><p><br></p>', 'U', '2023-05-14 22:55:30', '2023-05-14 22:55:32', 1),
(6, 'test', 'aaa', '/public/uploads/2024/04/19/1713535414199355.jpg', '<p> 这是一篇要发布的文章</p>', 'D', '2023-05-14 22:55:30', '2023-05-14 22:55:32', 1),
