CREATE TABLE `sys_menu` (
  `id` int(11) NOT NULL COMMENT '主键',
  `path` varchar(64) DEFAULT NULL COMMENT '路径',
  `component` varchar(64) DEFAULT NULL COMMENT '组件路径',
